from flask import Flask, jsonify, request
from flask_cors import CORS

app = Flask(__name__)
CORS(app)

# In-memory data storage
items = []
next_id = 1


@app.route("/api/health", methods=["GET"])
def health_check():
    return jsonify({"status": "healthy"}), 200


@app.route("/api/items", methods=["GET"])
def get_items():
    return jsonify(items), 200


@app.route("/api/items", methods=["POST"])
def create_item():
    global next_id
    data = request.get_json()

    if not data or "name" not in data:
        return jsonify({"error": "Missing required field: name"}), 400

    item = {"id": next_id, "name": data["name"]}
    next_id += 1
    items.append(item)

    return jsonify(item), 201

(function () {
    'use strict';

    const API_BASE = 'http://127.0.0.1:5000/api';

    // DOM elements
    const itemsContainer = document.getElementById('itemsContainer');
    const loadingIndicator = document.getElementById('loadingIndicator');
    const errorMessage = document.getElementById('errorMessage');
    const formMessage = document.getElementById('formMessage');
    const itemForm = document.getElementById('itemForm');
    const itemNameInput = document.getElementById('itemName');
    const itemDescriptionInput = document.getElementById('itemDescription');
    const submitBtn = itemForm.querySelector('button[type="submit"]');

    // ---- Helpers ----

    function showError(msg) {
        errorMessage.textContent = msg;
        errorMessage.classList.remove('hidden');
    }

    function hideError() {
        errorMessage.classList.add('hidden');
    }

    function showFormMessage(msg, type) {
        formMessage.textContent = msg;
        formMessage.className = 'message ' + type;
        formMessage.classList.remove('hidden');
        setTimeout(function () {
            formMessage.classList.add('hidden');
        }, 3000);
    }

    function showLoading() {
        loadingIndicator.classList.remove('hidden');
    }

    function hideLoading() {
        loadingIndicator.classList.add('hidden');
    }

    function setFormEnabled(enabled) {
        itemNameInput.disabled = !enabled;
        itemDescriptionInput.disabled = !enabled;
        submitBtn.disabled = !enabled;
    }

    // ---- API calls ----

    async function fetchItems() {
        const response = await fetch(API_BASE + '/items');
        if (!response.ok) {
            throw new Error('Failed to fetch items (HTTP ' + response.status + ')');
        }
        return response.json();
    }

    async function createItem(name, description) {
        const response = await fetch(API_BASE + '/items', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ name: name, description: description })
        });
        if (!response.ok) {
            const data = await response.json().catch(function () { return null; });
            throw new Error((data && data.error) || 'Failed to create item (HTTP ' + response.status + ')');
        }
        return response.json();
    }

    async function deleteItem(id) {
        const response = await fetch(API_BASE + '/items/' + id, {
            method: 'DELETE'
        });
        if (!response.ok) {
            throw new Error('Failed to delete item (HTTP ' + response.status + ')');
        }
        return response.json();
    }

    // ---- Render ----

    function renderItems(items) {
        if (!items || items.length === 0) {
            itemsContainer.innerHTML = '<li class="empty-state">No items yet. Add one above!</li>';
            return;
        }

        var html = '';
        items.forEach(function (item) {
            html +=
                '<li class="item-card" data-id="' + item.id + '">' +
                    '<div class="item-info">' +
                        '<div class="item-name">' + escapeHtml(item.name) + '</div>' +
                        (item.description
                            ? '<div class="item-description">' + escapeHtml(item.description) + '</div>'
                            : '') +
                    '</div>' +
                    '<div class="item-actions">' +
                        '<button class="delete-btn" data-id="' + item.id + '">Delete</button>' +
                    '</div>' +
                '</li>';
        });
        itemsContainer.innerHTML = html;

        // Attach delete handlers
        itemsContainer.querySelectorAll('.delete-btn').forEach(function (btn) {
            btn.addEventListener('click', function () {
                var id = btn.getAttribute('data-id');
                handleDelete(id);
            });
        });
    }

    function escapeHtml(text) {
        if (!text) return '';
        var div = document.createElement('div');
        div.appendChild(document.createTextNode(text));
        return div.innerHTML;
    }

    // ---- Handlers ----

    async function loadItems() {
        hideError();
        showLoading();

        try {
            var items = await fetchItems();
            renderItems(items);
        } catch (err) {
            showError(err.message);
            itemsContainer.innerHTML = '';
        } finally {
            hideLoading();
        }
    }

    async function handleSubmit(event) {
        event.preventDefault();

        var name = itemNameInput.value.trim();
        var description = itemDescriptionInput.value.trim();

        if (!name) {
            showFormMessage('Please enter a name.', 'error');
            return;
        }

        setFormEnabled(false);

        try {
            await createItem(name, description);
            showFormMessage('Item added successfully!', 'success');
            itemForm.reset();
            await loadItems();
        } catch (err) {
            showFormMessage(err.message, 'error');
        } finally {
            setFormEnabled(true);
        }
    }

    async function handleDelete(id) {
        hideError();

        try {
            await deleteItem(id);
            await loadItems();
        } catch (err) {
            showError(err.message);
        }
    }

    // ---- Init ----

    itemForm.addEventListener('submit', handleSubmit);
    loadItems();
})();

/* Reset & base */
*,
*::before,
*::after {
    box-sizing: border-box;
    margin: 0;
    padding: 0;
}

body {
    font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, Oxygen,
        Ubuntu, Cantarell, 'Helvetica Neue', sans-serif;
    background: #f5f7fa;
    color: #333;
    line-height: 1.6;
    min-height: 100vh;
    display: flex;
    justify-content: center;
    padding: 1rem;
}

.container {
    width: 100%;
    max-width: 640px;
    margin: 2rem auto;
}

/* Header */
header h1 {
    font-size: 1.75rem;
    font-weight: 700;
    color: #1a1a2e;
    margin-bottom: 1.5rem;
    text-align: center;
}

/* Sections */
section {
    background: #fff;
    border-radius: 10px;
    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.08);
    padding: 1.5rem;
    margin-bottom: 1.5rem;
}

section h2 {
    font-size: 1.15rem;
    font-weight: 600;
    color: #1a1a2e;
    margin-bottom: 1rem;
    border-bottom: 2px solid #eef0f5;
    padding-bottom: 0.5rem;
}

/* Form */
.form-group {
    margin-bottom: 1rem;
}

.form-group label {
    display: block;
    font-size: 0.875rem;
    font-weight: 500;
    color: #555;
    margin-bottom: 0.35rem;
}

.form-group input,
.form-group textarea {
    width: 100%;
    padding: 0.65rem 0.75rem;
    font-size: 1rem;
    border: 1px solid #d1d5db;
    border-radius: 6px;
    outline: none;
    transition: border-color 0.2s;
    font-family: inherit;
}

.form-group input:focus,
.form-group textarea:focus {
    border-color: #4f6ef7;
    box-shadow: 0 0 0 3px rgba(79, 110, 247, 0.15);
}

button[type="submit"] {
    display: inline-block;
    padding: 0.65rem 1.5rem;
    font-size: 1rem;
    font-weight: 600;
    color: #fff;
    background: #4f6ef7;
    border: none;
    border-radius: 6px;
    cursor: pointer;
    transition: background 0.2s;
}

button[type="submit"]:hover {
    background: #3b5de7;
}

button[type="submit"]:active {
    background: #2f4fd6;
}

button[type="submit"]:disabled {
    background: #a0b0f0;
    cursor: not-allowed;
}

/* Items list */
#itemsContainer {
    list-style: none;
}

.item-card {
    display: flex;
    justify-content: space-between;
    align-items: flex-start;
    padding: 0.85rem 0;
    border-bottom: 1px solid #eef0f5;
}

.item-card:last-child {
    border-bottom: none;
}

.item-info {
    flex: 1;
    min-width: 0;
}

.item-name {
    font-weight: 600;
    font-size: 1rem;
    color: #1a1a2e;
}

.item-description {
    font-size: 0.875rem;
    color: #6b7280;
    margin-top: 0.2rem;
    white-space: pre-wrap;
}

.item-actions {
    flex-shrink: 0;
    margin-left: 1rem;
}

.delete-btn {
    padding: 0.35rem 0.75rem;
    font-size: 0.8rem;
    font-weight: 500;
    color: #e53e3e;
    background: #fff5f5;
    border: 1px solid #fcc;
    border-radius: 5px;
    cursor: pointer;
    transition: background 0.2s;
}

.delete-btn:hover {
    background: #fee2e2;
}

/* Messages */
.message {
    padding: 0.65rem 0.85rem;
    border-radius: 6px;
    font-size: 0.875rem;
    margin-top: 0.75rem;
}

.message.hidden {
    display: none;
}

.message.error {
    background: #fff5f5;
    color: #c53030;
    border: 1px solid #fcc;
}

.message.success {
    background: #f0fff4;
    color: #276749;
    border: 1px solid #c6f6d5;
}

/* Loading */
.loading {
    text-align: center;
    color: #6b7280;
    font-size: 0.9rem;
    padding: 1rem 0;
}

.loading.hidden {
    display: none;
}

/* Empty state */
.empty-state {
    text-align: center;
    color: #9ca3af;
    padding: 2rem 0;
    font-size: 0.9rem;
}

/* Responsive */
@media (max-width: 480px) {
    body {
        padding: 0.5rem;
    }

    .container {
        margin: 1rem auto;
    }

    section {
        padding: 1rem;
    }

    .item-card {
        flex-direction: column;
        gap: 0.5rem;
    }

    .item-actions {
        margin-left: 0;
        align-self: flex-end;
    }
}

